/*
 * Canonical installer for m7-js-lib-app-popstatemanager.
 */

import PopStateManager from './PopStateManager.js';
import History from './History.js';
import State from './State.js';

const MOD = '[app.PopStateManager]';
const NAMESPACE_ID = 'app.PopStateManager';
const SERVICE_ID = 'app.popstatemanager';

function normalizeNamespace(value) {
    return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function assertLibWithHashSet(lib, label) {
    if (!lib || typeof lib !== 'object') {
        throw new Error(`${MOD} ${label} requires an m7-lib instance object.`);
    }

    if (!lib.hash || typeof lib.hash.set !== 'function') {
        throw new Error(`${MOD} ${label} requires lib.hash.set.`);
    }
}

function readNamespace(lib) {
    if (!lib || !lib.hash || typeof lib.hash.get !== 'function') {
        return {};
    }

    try {
        return normalizeNamespace(lib.hash.get(lib, NAMESPACE_ID));
    } catch (err) {
        return {};
    }
}

function resolveOrInstallNamespace(lib, opts = {}) {
    const candidate = opts && opts.namespace && typeof opts.namespace === 'object'
        ? opts.namespace
        : null;

    if (candidate && candidate.PopStateManager === PopStateManager) {
        return candidate;
    }

    const existing = readNamespace(lib);
    if (existing.PopStateManager === PopStateManager) {
        return existing;
    }

    return installNamespace(lib).namespace;
}

function isPopStateManagerLike(value) {
    if (!value || typeof value !== 'object') return false;
    if (value instanceof PopStateManager) return true;

    return typeof value.start === 'function'
        && typeof value.stop === 'function'
        && typeof value.set === 'function'
        && typeof value.push === 'function';
}

function assertPopStateManagerInstance(candidate, label) {
    if (!isPopStateManagerLike(candidate)) {
        throw new Error(`${MOD} ${label} must be a PopStateManager-compatible instance.`);
    }

    return candidate;
}

/**
 * Install PopStateManager constructors into the lib namespace registry.
 *
 * @param {Object} lib Initialized m7 lib instance.
 * @returns {{ namespace:Object, installedNamespace:boolean }}
 */
export function installNamespace(lib) {
    assertLibWithHashSet(lib, 'installNamespace(lib)');

    const namespace = readNamespace(lib);
    namespace.PopStateManager = PopStateManager;
    namespace.History = History;
    namespace.State = State;
    lib.hash.set(lib, NAMESPACE_ID, namespace);

    return {
        namespace,
        installedNamespace: true,
    };
}

/**
 * Install or reuse a shared PopStateManager service instance.
 *
 * @param {Object} lib Initialized m7 lib instance.
 * @param {Object} [opts={}]
 * @param {Object} [opts.conf]
 * @param {PopStateManager} [opts.instance]
 * @param {boolean} [opts.force=false]
 * @param {Object} [opts.namespace]
 * @param {Object} [opts.controller]
 * @param {Object} [opts.asserted]
 * @param {Object} [opts.env]
 * @param {Object} [opts.host]
 * @param {string} [opts.identifier]
 * @param {boolean} [opts.start=false]
 * @returns {{ namespace:Object, instance:PopStateManager|null, installedService:boolean }}
 */
export function installService(lib, opts = {}) {
    assertLibWithHashSet(lib, 'installService(lib)');

    const hasServiceSet = !!(lib.service && typeof lib.service.set === 'function');
    const hasServiceGet = !!(lib.service && typeof lib.service.get === 'function');
    const force = !!(opts && opts.force === true);
    const namespace = resolveOrInstallNamespace(lib, opts);
    const providedInstanceRaw =
        opts && Object.prototype.hasOwnProperty.call(opts, 'instance')
            ? opts.instance
            : null;
    const providedInstance =
        providedInstanceRaw == null
            ? null
            : assertPopStateManagerInstance(providedInstanceRaw, 'opts.instance');

    const existingInstanceRaw = hasServiceGet ? lib.service.get(SERVICE_ID) : null;
    const existingInstance = isPopStateManagerLike(existingInstanceRaw)
        ? existingInstanceRaw
        : null;

    let instance = null;
    if (!force && existingInstance) {
        instance = existingInstance;
    } else if (providedInstance) {
        instance = providedInstance;
    } else {
        const conf = opts && opts.conf && typeof opts.conf === 'object' ? opts.conf : {};
        instance = new PopStateManager({
            lib,
            conf,
            identifier: opts && opts.identifier,
            controller: opts && opts.controller,
            asserted: opts && opts.asserted,
            env: opts && opts.env,
            host: opts && opts.host,
        });
    }

    if (hasServiceSet) {
        lib.service.set(SERVICE_ID, instance);
    }

    namespace.instance = instance;
    lib.hash.set(lib, NAMESPACE_ID, namespace);

    if (opts && opts.start === true && instance && typeof instance.start === 'function') {
        instance.start();
    }

    return {
        namespace,
        instance,
        installedService: hasServiceSet,
    };
}

/**
 * Canonical install entrypoint.
 *
 * @param {Object} lib Initialized m7 lib instance.
 * @param {Object} [opts={}]
 * @returns {{ namespace:Object, instance:PopStateManager|null, installedService:boolean }}
 */
export function install(lib, opts = {}) {
    const namespaceResult = installNamespace(lib);
    return installService(lib, Object.assign({}, opts, { namespace: namespaceResult.namespace }));
}

export { PopStateManager, History, State, NAMESPACE_ID, SERVICE_ID };
export default install;
